#!/usr/bin/env bash
# Generated By: Claude Code (Claude Opus 4.7)
# SPDX-License-Identifier: Apache-2.0
#
# fabcheck — pure-bash fabrication detector for imports and file references.
# Scans tracked source files (or a git diff range) and verifies that every
# import / require / sourced file resolves to a stdlib module, a local path,
# or a declared dependency. Unresolved references are reported as `missing`.
#
# Supported languages: Python, JavaScript / TypeScript, Go, Rust, Shell.
#
# Output: <out-dir>/verdict.json with top-level {result, missing, warn,
# ok_count, files_scanned, languages, findings, duration_ms}.
#
# Exit codes:
#   0 — no missing references found (ok or warn-only)
#   1 — missing references found
#   2 — argument / environment error
#
# Usage:
#   fabcheck.sh [--out-dir <dir>] [--range <A..B>] [--language <csv>] [--list]
#
# Default scope: all tracked files in supported languages. Pass --range to
# scan only files changed in a git diff (useful for pre-commit / CI speed).

set -euo pipefail

OUT_DIR=".tmp-fabcheck"
RANGE=""
LANGUAGES_FILTER=""
LIST_ONLY="false"

print_list() {
    cat <<'EOF'
python     *.py
javascript *.js *.jsx *.ts *.tsx *.mjs *.cjs
go         *.go
rust       *.rs
shell      *.sh *.bash
EOF
}

usage() {
    cat <<'EOF'
fabcheck — detect hallucinated imports and missing file references.

Usage:
  fabcheck.sh [--out-dir <dir>] [--range <A..B>] [--language <csv>] [--list]

Options:
  --out-dir <dir>    Directory to write verdict.json into (default: .tmp-fabcheck)
  --range <A..B>     Scan diff instead of full tree (e.g., HEAD~1..HEAD)
  --language <csv>   Comma-separated language filter (python,javascript,go,rust,shell)
  --list             Print supported languages and file extensions, then exit
  -h, --help         Show this help

Exit: 0 = no missing; 1 = missing found; 2 = arg error.
EOF
}

while [ $# -gt 0 ]; do
    case "$1" in
        --out-dir)   OUT_DIR="$2"; shift 2 ;;
        --range)     RANGE="$2"; shift 2 ;;
        --language)  LANGUAGES_FILTER="$2"; shift 2 ;;
        --list)      LIST_ONLY="true"; shift ;;
        -h|--help)   usage; exit 0 ;;
        *) echo "fabcheck: unknown arg: $1" >&2; usage >&2; exit 2 ;;
    esac
done

if [ "$LIST_ONLY" = "true" ]; then
    print_list
    exit 0
fi

# Validate --range against a safe ref pattern so leading-dash values like
# `--stat` or whitespace-separated compound values cannot alter git semantics.
if [ -n "$RANGE" ]; then
    if ! [[ "$RANGE" =~ ^[a-zA-Z0-9_.^~:/-]+(\.\.\.?[a-zA-Z0-9_.^~:/-]+)?$ ]]; then
        echo "fabcheck: invalid --range: $RANGE" >&2
        exit 2
    fi
fi

# Tool prerequisites: git and jq always required; python3 only strictly
# required for Python files (detected below and reflected in verdict output).
for cmd in git jq; do
    if ! command -v "$cmd" >/dev/null 2>&1; then
        echo "fabcheck: required tool not found: $cmd" >&2
        exit 2
    fi
done

if ! git rev-parse --is-inside-work-tree >/dev/null 2>&1; then
    echo "fabcheck: must be run inside a git worktree" >&2
    exit 2
fi

mkdir -p "$OUT_DIR"
# Self-gitignore the output dir per the .tmp-<slug>/ convention
# (see standards repo common/tmp-dirs.md). Only written if absent, so a
# project using a pre-existing out-dir with its own policy is not disturbed.
if [ ! -e "$OUT_DIR/.gitignore" ]; then
    printf '*\n' > "$OUT_DIR/.gitignore" 2>/dev/null || true
fi
OUT="$OUT_DIR/verdict.json"

START_MS="$(date +%s%3N 2>/dev/null || python3 -c 'import time; print(int(time.time()*1000))')"

TMP_DIR="$(mktemp -d)"
TMP="$TMP_DIR/findings"
: > "$TMP"
trap 'rm -rf "$TMP_DIR"' EXIT

missing=0
warn=0
ok_count=0
files_scanned=0

add_finding() {
    local level="$1" symbol="$2" file="$3" lang="$4" msg="$5"
    jq -cn \
        --arg level "$level" \
        --arg symbol "$symbol" \
        --arg file "$file" \
        --arg lang "$lang" \
        --arg message "$msg" \
        '{level: $level, symbol: $symbol, file: $file, lang: $lang, message: $message}' \
        >> "$TMP"
    case "$level" in
        missing) missing=$((missing+1)) ;;
        warn)    warn=$((warn+1)) ;;
        ok)      ok_count=$((ok_count+1)) ;;
    esac
}

# Normalize a path that may not yet exist. GNU realpath -m is preferred;
# fall back to grealpath, then python stdlib. Returns empty on failure.
normalize_path() {
    local p="$1" out
    if out="$(realpath -m "$p" 2>/dev/null)" && [ -n "$out" ]; then
        printf '%s' "$out"; return 0
    fi
    if command -v grealpath >/dev/null 2>&1; then
        if out="$(grealpath -m "$p" 2>/dev/null)" && [ -n "$out" ]; then
            printf '%s' "$out"; return 0
        fi
    fi
    local py=""
    if command -v python3 >/dev/null 2>&1; then py="python3"
    elif command -v python  >/dev/null 2>&1; then py="python"
    fi
    if [ -n "$py" ]; then
        "$py" -c 'import os,sys; print(os.path.normpath(os.path.join(os.getcwd(), sys.argv[1])))' "$p" 2>/dev/null
        return 0
    fi
    return 1
}

# --- Language filter -------------------------------------------------------

language_enabled() {
    local lang="$1"
    [ -z "$LANGUAGES_FILTER" ] && return 0
    local csv=",${LANGUAGES_FILTER},"
    [[ "$csv" == *",${lang},"* ]]
}

lang_for_file() {
    case "$1" in
        *.py)                               echo "python" ;;
        *.js|*.jsx|*.ts|*.tsx|*.mjs|*.cjs)  echo "javascript" ;;
        *.go)                               echo "go" ;;
        *.rs)                               echo "rust" ;;
        *.sh|*.bash)                        echo "shell" ;;
        *) echo "" ;;
    esac
}

# --- Python dependency resolution (D3) -------------------------------------

# Stdlib heuristic — covers most real-world imports. The stdlib module names
# are listed literally; this is not executable code using any of them.
PY_STDLIB_RE='^(os|sys|re|json|math|datetime|time|pathlib|collections|itertools|functools|typing|dataclasses|abc|subprocess|argparse|logging|io|copy|enum|shutil|tempfile|socket|struct|hashlib|base64|uuid|urllib|http|email|csv|xml|html|threading|multiprocessing|asyncio|concurrent|contextlib|unittest|inspect|traceback|warnings|secrets|random|textwrap|glob|fnmatch|sqlite3|zlib|gzip|bz2|lzma|tarfile|zipfile|platform|locale|gettext|queue|signal|stat|fcntl|select|ctypes|weakref|operator|importlib|venv|ast|tokenize|keyword|builtins|types|string|marshal|shelve)$'

PY_DEPS_SOURCE="none"
PY_DEPS_FILE="$TMP_DIR/py_declared"
: > "$PY_DEPS_FILE"

collect_py_deps() {
    if [ -f requirements.txt ]; then
        PY_DEPS_SOURCE="requirements.txt"
        awk '
            { sub(/#.*/, ""); gsub(/[[:space:]]/, "") }
            /^$/ { next }
            { sub(/[<>=!~;].*$/, ""); sub(/\[.*$/, ""); if (length($0)>0) print tolower($0) }
        ' requirements.txt >> "$PY_DEPS_FILE" || true
    fi
    if [ -f pyproject.toml ]; then
        if [ "$PY_DEPS_SOURCE" = "none" ]; then
            PY_DEPS_SOURCE="pyproject.toml"
        else
            PY_DEPS_SOURCE="${PY_DEPS_SOURCE}+pyproject.toml"
        fi
        # Parse both [project].dependencies and [project.optional-dependencies].
        # Optional groups (dev/test/docs/etc) are included so test files that
        # import pytest / fixtures do not show up as "missing" in projects
        # that keep those under optional-dependencies.
        awk '
            /^\[project\]/                        { in_project=1; in_optional=0; next }
            /^\[project\.optional-dependencies\]/ { in_project=0; in_optional=1; next }
            /^\[/                                  { in_project=0; in_optional=0; in_deps=0; next }
            in_project && /^dependencies[[:space:]]*=/ { in_deps=1; sub(/.*=[[:space:]]*\[/, "") }
            in_optional && /=[[:space:]]*\[/           { in_deps=1; sub(/.*=[[:space:]]*\[/, "") }
            in_deps {
                gsub(/\]/, ""); gsub(/"/, ""); gsub(/,/, "\n")
                n=split($0, arr, "\n")
                for (i=1;i<=n;i++) {
                    v=arr[i]; gsub(/[[:space:]]/, "", v)
                    sub(/[<>=!~;].*$/, "", v); sub(/\[.*$/, "", v)
                    if (length(v)>0) print tolower(v)
                }
                if ($0 ~ /\]/) in_deps=0
            }
        ' pyproject.toml >> "$PY_DEPS_FILE" || true
    fi
}

PY_PKG_MAP="$TMP_DIR/py_pkg_map.json"
echo '{}' > "$PY_PKG_MAP"
PY_STDLIB_SET="$TMP_DIR/py_stdlib.txt"
: > "$PY_STDLIB_SET"
PY_ENV_METADATA_AVAILABLE="false"
PY_RESOLUTION_MODE="fallback"

# D3: build top-level-import -> [dist-names] map from importlib.metadata AND
# populate the stdlib module set from sys.stdlib_module_names (Python 3.10+).
# Using the interpreter's own stdlib list avoids curating a hand-written regex.
collect_py_pkg_map() {
    command -v python3 >/dev/null 2>&1 || return 0
    python3 - >"$PY_PKG_MAP.new" 2>/dev/null <<'PY' || return 0
import json, sys
out = {"packages": {}, "stdlib": []}
try:
    from importlib.metadata import packages_distributions
    out["packages"] = packages_distributions()
except Exception:
    pass
try:
    out["stdlib"] = sorted(sys.stdlib_module_names)
except Exception:
    pass
print(json.dumps(out))
PY
    if [ -s "$PY_PKG_MAP.new" ]; then
        jq -c '.packages // {}' "$PY_PKG_MAP.new" > "$PY_PKG_MAP" 2>/dev/null || echo '{}' > "$PY_PKG_MAP"
        jq -r '.stdlib[]? // empty' "$PY_PKG_MAP.new" 2>/dev/null > "$PY_STDLIB_SET" || : > "$PY_STDLIB_SET"
        local entries
        entries="$(jq 'length' "$PY_PKG_MAP" 2>/dev/null || echo 0)"
        if [ "${entries:-0}" -gt 0 ]; then
            PY_ENV_METADATA_AVAILABLE="true"
            PY_RESOLUTION_MODE="precise"
        fi
    fi
}

# Precise resolution: look up top-level import in the env map, return the
# list of dist names (one per line). Empty output if no entry.
py_dists_for_import() {
    local top="$1"
    jq -r --arg k "$top" '.[$k] // [] | .[]' "$PY_PKG_MAP" 2>/dev/null || true
}

py_is_stdlib() {
    # Use sys.stdlib_module_names when the env helper populated it; otherwise
    # fall back to the embedded regex heuristic.
    local top="$1"
    if [ -s "$PY_STDLIB_SET" ]; then
        grep -Fxq -- "$top" "$PY_STDLIB_SET"
        return $?
    fi
    [[ "$top" =~ $PY_STDLIB_RE ]]
}

py_dep_declared() {
    # Case-insensitive exact match against declared deps (already lowercased).
    # `-- "$pattern"` so leading-dash inputs can't be parsed as grep options.
    local name_lower
    name_lower="$(printf '%s' "$1" | tr '[:upper:]' '[:lower:]')"
    [ -s "$PY_DEPS_FILE" ] || return 1
    if grep -Fxq -- "$name_lower" "$PY_DEPS_FILE"; then return 0; fi
    # Tolerate dash/underscore variants on the dist-name side.
    if grep -Fxq -- "${name_lower//_/-}" "$PY_DEPS_FILE"; then return 0; fi
    if grep -Fxq -- "${name_lower//-/_}" "$PY_DEPS_FILE"; then return 0; fi
    return 1
}

classify_py_unknown_import() {
    # $1 = full dotted module, $2 = top-level package, $3 = source file
    local mod="$1" top="$2" src="$3"
    if [ "$PY_DEPS_SOURCE" = "none" ]; then
        add_finding "warn" "$mod" "$src" "python" "third-party or unresolved (no requirements file to cross-check)"
        return
    fi
    if [ "$PY_RESOLUTION_MODE" = "precise" ]; then
        local dists dist
        dists="$(py_dists_for_import "$top")"
        if [ -n "$dists" ]; then
            while IFS= read -r dist; do
                [ -z "$dist" ] && continue
                if py_dep_declared "$dist"; then
                    add_finding "ok" "$mod" "$src" "python" "third-party (import $top -> dist $dist in ${PY_DEPS_SOURCE})"
                    return
                fi
            done <<< "$dists"
            local dist_csv
            dist_csv="$(echo "$dists" | paste -sd, -)"
            add_finding "missing" "$mod" "$src" "python" "top-level $top maps to dists [$dist_csv], none in ${PY_DEPS_SOURCE}"
            return
        fi
        # No env mapping for this top-level; fall through to name-normalized fallback.
    fi
    if py_dep_declared "$top"; then
        add_finding "ok" "$mod" "$src" "python" "third-party (declared in ${PY_DEPS_SOURCE})"
    else
        local reason="not in stdlib, not local, not in ${PY_DEPS_SOURCE}"
        if [ "$PY_RESOLUTION_MODE" = "fallback" ]; then
            reason="$reason (resolution_mode=fallback, no-env-metadata)"
            add_finding "warn" "$mod" "$src" "python" "$reason"
        else
            add_finding "missing" "$mod" "$src" "python" "$reason"
        fi
    fi
}

# --- Per-language line parsers --------------------------------------------

# Each parser takes: $1 = content line (no diff `+` prefix), $2 = source file.

parse_python_line() {
    local line="$1" src="$2" mod top
    # Match `from X import` or `import X` where X starts with an identifier
    # char (underscore or letter). This prevents leading-dot relative imports
    # (`from .foo import bar`) from being captured as the module token; those
    # are handled by a dedicated regex below.
    if [[ "$line" =~ ^[[:space:]]*from[[:space:]]+(\.+)([a-zA-Z0-9_.]*)[[:space:]]+import ]]; then
        # Relative import: leading dots refer to the current package. Always local.
        add_finding "ok" "${BASH_REMATCH[1]}${BASH_REMATCH[2]}" "$src" "python" "relative import"
        return 0
    elif [[ "$line" =~ ^[[:space:]]*from[[:space:]]+([a-zA-Z_][a-zA-Z0-9_.]*)[[:space:]]+import ]]; then
        mod="${BASH_REMATCH[1]}"
    elif [[ "$line" =~ ^[[:space:]]*import[[:space:]]+([a-zA-Z_][a-zA-Z0-9_.]*) ]]; then
        mod="${BASH_REMATCH[1]}"
    else
        return 0
    fi
    top="${mod%%.*}"
    if py_is_stdlib "$top"; then
        add_finding "ok" "$mod" "$src" "python" "stdlib"
    elif [ -d "$top" ] || [ -f "${top}.py" ]; then
        add_finding "ok" "$mod" "$src" "python" "local"
    else
        classify_py_unknown_import "$mod" "$top" "$src"
    fi
}

parse_javascript_line() {
    local line="$1" src="$2" path dir_of_file resolved
    if [[ "$line" =~ from[[:space:]]+[\'\"]([^\'\"]+)[\'\"] ]] \
       || [[ "$line" =~ require\([[:space:]]*[\'\"]([^\'\"]+)[\'\"] ]]; then
        path="${BASH_REMATCH[1]}"
        case "$path" in
            ./*|../*|/*)
                dir_of_file="$(dirname "$src")"
                resolved="$(cd "$dir_of_file" 2>/dev/null && normalize_path "$path" || echo "")"
                if [ -n "$resolved" ] && { [ -f "$resolved" ] || [ -f "${resolved}.js" ] || [ -f "${resolved}.ts" ] || [ -f "${resolved}/index.js" ] || [ -d "$resolved" ]; }; then
                    add_finding "ok" "$path" "$src" "javascript" "resolved"
                else
                    add_finding "missing" "$path" "$src" "javascript" "unresolved relative import"
                fi
                ;;
            *)
                add_finding "warn" "$path" "$src" "javascript" "node_modules or alias (uncheckable without node)"
                ;;
        esac
    fi
}

parse_go_line() {
    local line="$1" src="$2" pkg
    if [[ "$line" =~ ^[[:space:]]*import[[:space:]]+[\"]([^\"]+)[\"] ]]; then
        pkg="${BASH_REMATCH[1]}"
        add_finding "warn" "$pkg" "$src" "go" "package (uncheckable without go toolchain)"
    fi
}

parse_rust_line() {
    local line="$1" src="$2" crate
    if [[ "$line" =~ ^[[:space:]]*use[[:space:]]+([a-zA-Z0-9_:]+) ]]; then
        crate="${BASH_REMATCH[1]%%::*}"
        add_finding "warn" "$crate" "$src" "rust" "crate (uncheckable without cargo)"
    fi
}

parse_shell_line() {
    local line="$1" src="$2" target dir_of_file
    if [[ "$line" =~ ^[[:space:]]*(source|\.)[[:space:]]+([^[:space:]]+) ]]; then
        target="${BASH_REMATCH[2]}"
        if [[ "$target" =~ \$ ]]; then
            add_finding "warn" "$target" "$src" "shell" "dynamic path"
        else
            dir_of_file="$(dirname "$src")"
            if [ -f "$target" ] || [ -f "$dir_of_file/$target" ]; then
                add_finding "ok" "$target" "$src" "shell" "found"
            else
                add_finding "missing" "$target" "$src" "shell" "sourced file not found"
            fi
        fi
    fi
}

dispatch_line() {
    local lang="$1" line="$2" src="$3"
    case "$lang" in
        python)     parse_python_line "$line" "$src" ;;
        javascript) parse_javascript_line "$line" "$src" ;;
        go)         parse_go_line "$line" "$src" ;;
        rust)       parse_rust_line "$line" "$src" ;;
        shell)      parse_shell_line "$line" "$src" ;;
    esac
}

# --- Scan modes ------------------------------------------------------------

# Track which languages actually had files scanned (for verdict.languages).
declare -A LANG_SEEN=()

scan_full_file() {
    local file="$1" lang
    lang="$(lang_for_file "$file")"
    [ -n "$lang" ] || return 0
    language_enabled "$lang" || return 0
    [ -f "$file" ] || return 0
    LANG_SEEN[$lang]=1
    files_scanned=$((files_scanned+1))
    while IFS= read -r line || [ -n "$line" ]; do
        dispatch_line "$lang" "$line" "$file"
    done < "$file"
}

scan_full_tree() {
    while IFS= read -r -d '' file; do
        scan_full_file "$file"
    done < <(git ls-files -z)
}

scan_range() {
    local current_file="" current_lang=""
    local -A seen_files=()
    while IFS= read -r line; do
        if [[ "$line" =~ ^diff\ --git\ a/(.+)\ b/(.+)$ ]]; then
            current_file="${BASH_REMATCH[2]}"
            current_lang="$(lang_for_file "$current_file")"
            if [ -n "$current_lang" ] && language_enabled "$current_lang"; then
                LANG_SEEN[$current_lang]=1
                if [ -z "${seen_files[$current_file]:-}" ]; then
                    seen_files[$current_file]=1
                    files_scanned=$((files_scanned+1))
                fi
            fi
            continue
        fi
        [ -n "$current_lang" ] && language_enabled "$current_lang" || continue
        [[ "$line" =~ ^\+[^+] ]] || continue
        dispatch_line "$current_lang" "${line:1}" "$current_file"
    done < <(git diff "$RANGE")
}

# --- Main ------------------------------------------------------------------

# Collect Python declared deps up-front (cheap even for non-Python projects).
collect_py_deps
# D3: collect the env's import-name -> dist-name map once (Python only).
collect_py_pkg_map

if [ -n "$RANGE" ]; then
    scan_range
else
    scan_full_tree
fi

if [ "$missing" -gt 0 ]; then
    result="fail"
else
    result="pass"
fi

END_MS="$(date +%s%3N 2>/dev/null || python3 -c 'import time; print(int(time.time()*1000))')"
DURATION_MS=$((END_MS - START_MS))

# Build language-metadata object conditionally — include an entry only for
# languages actually present in the scan (per LANG_SEEN).
LANGS_JSON='{}'
add_lang() {
    local key="$1" body="$2"
    LANGS_JSON="$(jq -c --arg k "$key" --argjson v "$body" '. + {($k): $v}' <<<"$LANGS_JSON")"
}

if [ -n "${LANG_SEEN[python]:-}" ]; then
    py_body="$(jq -cn \
        --arg src "$PY_DEPS_SOURCE" \
        --arg mode "$PY_RESOLUTION_MODE" \
        --argjson meta "$PY_ENV_METADATA_AVAILABLE" \
        '{declared_deps_source: $src, env_metadata_available: $meta, resolution_mode: $mode}')"
    add_lang "python" "$py_body"
fi
for L in javascript go rust shell; do
    if [ -n "${LANG_SEEN[$L]:-}" ]; then
        add_lang "$L" '{}'
    fi
done

ITEMS_JSON='[]'
if [ -s "$TMP" ]; then
    ITEMS_JSON="$(jq -cs '.' "$TMP")"
fi

jq -n \
    --arg result "$result" \
    --argjson missing "$missing" \
    --argjson warn "$warn" \
    --argjson ok_count "$ok_count" \
    --argjson files_scanned "$files_scanned" \
    --argjson languages "$LANGS_JSON" \
    --argjson findings "$ITEMS_JSON" \
    --argjson duration_ms "$DURATION_MS" \
    '{result: $result,
      missing: $missing,
      warn: $warn,
      ok_count: $ok_count,
      files_scanned: $files_scanned,
      languages: $languages,
      findings: $findings,
      duration_ms: $duration_ms}' \
    > "$OUT"

echo "fabcheck: scanned=$files_scanned missing=$missing warn=$warn ok=$ok_count result=$result (verdict: $OUT)"

if [ "$missing" -gt 0 ]; then
    exit 1
fi
exit 0
